import Avatar from '@/components/odyssey/components/primitives/avatar';

export const AvatarDemo = () => {
  return (
    <div className="flex flex-col items-center gap-8">
      <div className="flex items-center gap-4">
        <Avatar color="blue" size="sm" />
        <Avatar color="blue" size="md" />
        <Avatar color="blue" size="lg" />
      </div>
      <div className="flex flex-wrap justify-center gap-3">
        {(
          [
            'blue',
            'orange',
            'red',
            'green',
            'purple',
            'yellow',
            'cyan',
            'pink',
            'indigo',
            'lime',
            'turquoise',
            'violet',
          ] as const
        ).map((color) => (
          <Avatar key={color} color={color} size="md" />
        ))}
      </div>
      <div className="flex items-center gap-4">
        <Avatar color="purple" size="md" shape="circle" />
        <Avatar color="purple" size="md" shape="squircle" />
        <Avatar color="purple" size="md" shape="square" />
      </div>
    </div>
  );
};

export default AvatarDemo;
